// ==========================================
// EXECUTION CONTROL BRAIN
// Strategy Alignment + Conflict Detection
// + Risk Assessment before execution
// ==========================================
const incoming = $('Control Gate Webhook').first()?.json?.body || $('Control Gate Webhook').first()?.json || {};
const decisions = incoming.decisions || [];
const strategy = $('Read Current Strategy').first()?.json || {};
const recentDecisions = $('Read Recent Decisions').all().map(d => d.json);

// === EXTRACT STRATEGY CONTEXT ===
const primaryFocus = strategy['Primary Focus'] || strategy.primary_focus || 'revenue';
const primaryBet = strategy['Primary Bet'] || strategy.primary_bet || '';
const killZone = strategy['Kill Zone'] || strategy.kill_zone || '';
const priorityScore = strategy['Priority Score'] || strategy.priority_score || 5;
const kpiTarget = strategy['KPI Target'] || strategy.kpi_target || 1500;
const kpiActual = strategy['KPI Actual'] || strategy.kpi_actual || 0;
const contentPct = strategy['Content Pct'] || strategy.content_pct || 40;
const salesPct = strategy['Sales Pct'] || strategy.sales_pct || 30;
const direction = strategy['Direction'] || strategy.direction || '';
const mandate = strategy['Mandate'] || strategy.mandate || '';

// === FOCUS-TO-KEYWORD MAP ===
const focusKeywords = {
  conversion: ['close', 'convert', 'sale', 'إغلاق', 'تحويل', 'بيع', 'وردة', 'warda', 'pricing'],
  revenue: ['revenue', 'price', 'upsell', 'إيراد', 'سعر', 'دفع', 'عرض', 'pricing'],
  audience_growth: ['content', 'video', 'reach', 'scale', 'محتوى', 'فيديو', 'إنتاج', 'نشر', 'hook'],
  retention: ['quality', 'retain', 'experience', 'جودة', 'تجربة', 'متابعة'],
  brand_awareness: ['brand', 'awareness', 'reach', 'براند', 'وعي', 'وصول'],
  product_quality: ['bug', 'fix', 'improve', 'إصلاح', 'تحسين', 'جودة', 'أمان', 'security']
};

const focusWords = focusKeywords[primaryFocus] || [];

// === CONFLICT DETECTION ===
// Check if any recent decisions conflict with incoming ones
const recentActions = recentDecisions.flatMap(d => {
  try { return JSON.parse(d['Decisions JSON'] || '[]'); } catch { return []; }
});

// === EVALUATE EACH DECISION ===
const evaluated = decisions.map((decision, i) => {
  const actionLower = (decision.action || '').toLowerCase();
  const agentLower = (decision.target_agent || '').toLowerCase();

  // 1. Strategy Alignment Score (0-100)
  let alignmentScore = 50; // neutral
  let alignmentReason = '';

  // Check if action matches primary focus keywords
  const matchesKeywords = focusWords.some(kw => actionLower.includes(kw) || agentLower.includes(kw));
  if (matchesKeywords) {
    alignmentScore += 30;
    alignmentReason = `يتوافق مع التركيز: ${primaryFocus}`;
  }

  // Check if action is in kill zone
  const killZoneLower = killZone.toLowerCase();
  if (killZoneLower && (actionLower.includes(killZoneLower) || killZoneLower.split(/[,،]/).some(k => actionLower.includes(k.trim())))) {
    alignmentScore -= 40;
    alignmentReason = `⚠️ في Kill Zone: ${killZone}`;
  }

  // Check if action matches primary bet
  if (primaryBet && actionLower.includes(primaryBet.toLowerCase().substring(0, 20))) {
    alignmentScore += 20;
    alignmentReason += ` | يخدم الرهان الرئيسي`;
  }

  // Resource allocation check
  if (agentLower.includes('content') && contentPct < 20) {
    alignmentScore -= 15;
    alignmentReason += ` | الاستراتيجية تقلل المحتوى (${contentPct}%)`;
  }
  if ((agentLower.includes('warda') || agentLower.includes('sales')) && salesPct < 15) {
    alignmentScore -= 15;
    alignmentReason += ` | الاستراتيجية تقلل المبيعات (${salesPct}%)`;
  }

  // 2. KPI Impact Check
  let kpiImpact = 'neutral';
  if (primaryFocus === 'conversion' && (agentLower.includes('warda') || actionLower.includes('close'))) {
    kpiImpact = 'positive';
    alignmentScore += 10;
  } else if (primaryFocus === 'audience_growth' && agentLower.includes('content')) {
    kpiImpact = 'positive';
    alignmentScore += 10;
  } else if (primaryFocus === 'revenue' && (actionLower.includes('price') || actionLower.includes('سعر'))) {
    kpiImpact = 'positive';
    alignmentScore += 10;
  }

  // 3. Conflict Detection
  let hasConflict = false;
  let conflictWith = '';
  recentActions.forEach(recent => {
    const recentAction = (recent.action || '').toLowerCase();
    // Same agent, contradicting action
    if (recent.target_agent === decision.target_agent && recentAction !== actionLower) {
      // Check for opposite directions
      if ((actionLower.includes('scale') && recentAction.includes('kill')) ||
          (actionLower.includes('ارفع') && recentAction.includes('خفض')) ||
          (actionLower.includes('أوقف') && recentAction.includes('استمر'))) {
        hasConflict = true;
        conflictWith = recent.action;
        alignmentScore -= 20;
      }
    }
  });

  // 4. Risk Assessment
  const riskLevel = decision.risk || 'low';
  if (riskLevel === 'high') alignmentScore -= 10;
  if (riskLevel === 'critical') alignmentScore -= 20;

  // Clamp score
  alignmentScore = Math.max(0, Math.min(100, alignmentScore));

  // 5. Final Verdict
  let verdict = 'EXECUTE';
  let verdictReason = '';

  if (alignmentScore >= 70) {
    verdict = 'EXECUTE';
    verdictReason = 'متوافق مع الاستراتيجية';
  } else if (alignmentScore >= 40) {
    verdict = 'MODIFY';
    verdictReason = 'يحتاج تعديل ليتوافق مع الاستراتيجية';
  } else {
    verdict = 'BLOCK';
    verdictReason = 'يتعارض مع الاستراتيجية الحالية';
  }

  // Override: if in kill zone, always block
  if (alignmentScore <= 20) verdict = 'BLOCK';

  return {
    ...decision,
    control: {
      alignment_score: alignmentScore,
      alignment_reason: alignmentReason || 'تقييم عام',
      kpi_impact: kpiImpact,
      has_conflict: hasConflict,
      conflict_with: conflictWith,
      risk_level: riskLevel,
      verdict,
      verdict_reason: verdictReason
    }
  };
});

// Separate by verdict
const toExecute = evaluated.filter(d => d.control.verdict === 'EXECUTE');
const toModify = evaluated.filter(d => d.control.verdict === 'MODIFY');
const toBlock = evaluated.filter(d => d.control.verdict === 'BLOCK');

return {
  json: {
    timestamp: new Date().toISOString(),
    strategy_context: {
      primary_focus: primaryFocus,
      primary_bet: primaryBet,
      kill_zone: killZone,
      direction,
      mandate,
      kpi_progress: kpiTarget > 0 ? Math.round(kpiActual / kpiTarget * 100) : 0
    },
    summary: {
      total: evaluated.length,
      execute: toExecute.length,
      modify: toModify.length,
      block: toBlock.length
    },
    decisions: {
      execute: toExecute,
      modify: toModify,
      block: toBlock
    },
    all_evaluated: evaluated
  }
};

